-- Migration: add new columns to seed_lots
ALTER TABLE seed_lots
  ADD COLUMN IF NOT EXISTS supplier TEXT,
  ADD COLUMN IF NOT EXISTS product_link TEXT,
  ADD COLUMN IF NOT EXISTS item_number TEXT,
  ADD COLUMN IF NOT EXISTS vendor_short TEXT,
  ADD COLUMN IF NOT EXISTS gpc_code TEXT,
  ADD COLUMN IF NOT EXISTS type TEXT,
  ADD COLUMN IF NOT EXISTS success TEXT,
  ADD COLUMN IF NOT EXISTS grow_time TEXT,
  ADD COLUMN IF NOT EXISTS used_in TEXT,
  ADD COLUMN IF NOT EXISTS currently_grown BOOLEAN;

-- Import 49 seed lots from Produce List
ON CONFLICT (qr_code) DO UPDATE SET
  seed_name = EXCLUDED.seed_name,
  supplier = EXCLUDED.supplier,
  product_link = EXCLUDED.product_link,
  item_number = EXCLUDED.item_number,
  vendor_short = EXCLUDED.vendor_short,
  gpc_code = EXCLUDED.gpc_code,
  type = EXCLUDED.type,
  success = EXCLUDED.success,
  grow_time = EXCLUDED.grow_time,
  used_in = EXCLUDED.used_in,
  currently_grown = EXCLUDED.currently_grown;
